'use client';

interface AccordionButtonProps {
  children: React.ReactNode;
  variant: 'delete' | 'edit';
  handleButtonClick?: () => void;
}
export default function AccordionButton({
  children,
  variant,
  handleButtonClick
}: AccordionButtonProps) {
  const variants = {
    delete: 'bg-alert hover:bg-alert/70 text-white',
    edit: 'bg-primary hover:bg-primary/70 text-white'
  };
  return (
    <button onClick={handleButtonClick} className={`${variants[variant]}`}>
      {children}
    </button>
  );
}
